import"./hoisted.Cft9kqsr.js";document.addEventListener("DOMContentLoaded",()=>{const c=document.querySelectorAll(".btn-minus-list"),r=document.querySelectorAll(".btn-plus-list");c.forEach(n=>{n.addEventListener("click",a=>{const e=a.currentTarget.dataset.id,t=document.getElementById(`qty-${e}`);if(t){let d=parseInt(t.value)||1;d>1&&(t.value=(d-1).toString())}})}),r.forEach(n=>{n.addEventListener("click",a=>{const e=a.currentTarget.dataset.id,t=document.getElementById(`qty-${e}`);if(t){let d=parseInt(t.value)||1;t.value=(d+1).toString()}})}),document.querySelectorAll('input[type="number"]').forEach(n=>{n.addEventListener("change",a=>{const e=a.target;let t=parseInt(e.value);(isNaN(t)||t<1)&&(e.value="1")})}),document.querySelectorAll(".btn-add-to-cart-list").forEach(n=>{n.addEventListener("click",a=>{const e=a.currentTarget,t=e.dataset.id,d=JSON.parse(e.dataset.product||"{}"),o=document.getElementById(`qty-${t}`),s=parseInt(o?o.value:"1")||1;window.addToCartGlobal&&window.addToCartGlobal({...d,quantity:s})})})});
